-- ─── Levels ───────────────────────────────────────────────────────────────

INSERT INTO public.levels (id, number, name, description) VALUES
  ('4d355fb9-493f-4101-9a9f-bc7ec6f85ca6', 1, 'Foundations', 'Core PE concepts — fund structure, key players, deal mechanics, and return metrics. No prior finance knowledge required.'),
  ('68cca497-8e72-4064-9781-f387f05c8492', 2, 'Financial Analysis', 'Read, interpret, and analyse financial statements through the lens of a PE investor. Understand the metrics PE firms use to evaluate businesses.'),
  ('d348d0b0-a934-42b7-82ed-d95ce318cd15', 3, 'Valuation', 'Understand how PE firms price and evaluate businesses using trading comps, precedent transactions, DCF, and LBO model construction.'),
  ('84f9bd80-690c-4b2e-845f-bac3459e09c7', 4, 'Due Diligence', 'Investigate targets before acquisition. Understand how commercial, financial, legal, operational, and ESG diligence feeds into deal decisions.'),
  ('156004ab-c0e6-4690-9b7e-c695ccf5b16f', 5, 'Value Creation', 'How PE firms improve businesses post-acquisition — from 100-day plans to buy-and-build strategy, pricing, and operational excellence.'),
  ('ea48ac0c-0480-43dd-92d9-096a11ed3698', 6, 'Exit Strategies', 'Selling portfolio companies and returning capital — trade sales, IPOs, secondary buyouts, dividend recaps, and exit preparation.'),
  ('1be0566b-703c-41ab-ac96-49b024417378', 7, 'Fund Operations', 'Running a PE firm — fundraising, LP relationships, fund terms, co-investments, GP economics, and regulatory framework.'),
  ('da8c23e6-04be-44ba-83e1-9bc07adb0bee', 8, 'Specialised Strategies', 'Alternative PE approaches beyond buyouts — growth equity, private credit, distressed, infrastructure, secondaries, and ESG/impact.'),
  ('878b07fd-c020-4bea-94c2-3a13270a5772', 9, 'Global Markets', 'PE across geographies, currencies, and regulatory regimes — European and Asian markets, cross-border transactions, and macro cycles.'),
  ('cce5b1f3-b01d-492e-914d-3d3b8e447cce', 10, 'Mastery', 'Senior-level synthesis — investment thesis construction, portfolio strategy, ethics, and career navigation in PE.'),
  ('37f39be5-11bd-43e6-b5dc-7366b920c3f4', 11, 'Advanced', 'Specialist deep dives for practitioners — financial modelling, behavioural finance, technology, people leadership, sector analysis, negotiation, accounting, restructuring, and tax structuring.')
ON CONFLICT (id) DO NOTHING;


